#!/bin/bash\n# Script para verificar la seguridad antes de subir a GitHub\n\necho \"🔒 VERIFICADOR DE SEGURIDAD - FORMSPREE\"\necho \"=======================================\"\necho \"\"\n\n# 1. Verificar que el token real NO está en los archivos\necho \"[1/4] Buscando tokens reales en los archivos...\"\nif grep -r \"xojpvwqw\\|xozgwqdo\" .; then\n    echo \"❌ ERROR: Encontré un token real. Cámbialo por TU_TOKEN_FORMSPREE\"\n    exit 1\nelse\n    echo \"✅ OK: No hay tokens reales en los archivos\"\nfi\n\necho \"\"\n\n# 2. Verificar que .gitignore existe y contiene .env\necho \"[2/4] Verificando .gitignore...\"\nif [ ! -f .gitignore ]; then\n    echo \"❌ ERROR: No existe .gitignore\"\n    exit 1\nfi\n\nif grep -q ^\".env\" .gitignore; then\n    echo \"✅ OK: .gitignore contiene .env\"\nelse\n    echo \"⚠️  ADVERTENCIA: .gitignore no contiene .env\"\nfi\n\necho \"\"\n\n# 3. Verificar que .env NO existe\necho \"[3/4] Verificando archivos .env...\"\nif [ -f .env ]; then\n    echo \"⚠️  ADVERTENCIA: Existe archivo .env (no lo subas)\"\nelse\n    echo \"✅ OK: No existe .env local\"\nfi\n\necho \"\"\n\n# 4. Verificar que .env-example SÍ existe\necho \"[4/4] Verificando .env-example...\"\nif [ -f .env-example ]; then\n    echo \"✅ OK: Existe .env-example (plantilla segura)\"\nelse\n    echo \"⚠️  ADVERTENCIA: No existe .env-example\"\nfi\n\necho \"\"\necho \"=======================================\"\necho \"✅ LISTO PARA SUBIR A GITHUB\"\necho \"=======================================\"\necho \"\"\necho \"Próximos pasos:\"\necho \"1. git add .\"\necho \"2. git commit -m 'Estructura Bootstrap con Formspree seguro'\"\necho \"3. git push origin main\"\n"